sql:
SELECT name 
FROM recipes 
WHERE difficulty = 'easy';

SELECT name, minutes
FROM recipes
WHERE minutes <= 30;

SELECT u.name, u.email
FROM users u
JOIN reviews r ON u.user_id = r.user_id;

SELECT AVG(calories), AVG(total_fat), AVG(sugar), AVG(sodium), AVG(protein), AVG(sat_fat), AVG(carbs), AVG(fiber), AVG(cholesterol)
FROM nutrition
WHERE recipe_id IN (SELECT recipe_id FROM recipes WHERE minutes <= 60);

SELECT COUNT(*) AS num_contributors FROM contributors
UNION ALL
SELECT COUNT(*) AS num_users FROM users;

SELECT recipe_id, AVG(ingredient_id) AS average_ingredient_id
FROM recipe_ingredients
GROUP BY recipe_id;

SELECT r.recipe_id, r.name
FROM recipes r
WHERE r.minutes <= 60 AND r.contributor_id = 5;

SELECT AVG(nutrition.calories) AS AvgCaloriesPerRecipe
FROM nutrition
JOIN recipes ON nutrition.recipe_id = recipes.recipe_id;
